/* ================================================================== */
/* CHARACTERS                                                          */
/* ================================================================== */
//
// One construction grammar shared by every animal (character-design.md):
//   soft body ellipse + an oversized round head sitting high & slightly
//   forward + a single cream eye-dot (now with a tiny highlight + a blink) +
//   a soft cheek blush + an amber face accent + short rounded limbs + a gentle
//   smile. A soft rim-light and a faint contact shadow give it form.
// Poses transform the SAME base — they never redraw the body.
//
// Local coordinate convention: origin (0,0) = where the feet meet the ground;
// the body sits above in -y; the character faces RIGHT by default (flip for
// pairs).

type PoseInfo = {
  headTilt: number;
  legSpread: number;
  legOffset: number;
  limbUp: boolean;
  offer: boolean;
  curl: boolean;
};

function poseInfo(pose: Pose | string): PoseInfo {
  switch (pose) {
    case "looking_up":
      return { headTilt: -16, legSpread: 6, legOffset: 0, limbUp: false, offer: false, curl: false };
    case "offering":
      return { headTilt: -4, legSpread: 6, legOffset: 0, limbUp: false, offer: true, curl: false };
    case "curled":
      return { headTilt: 6, legSpread: 5, legOffset: 0, limbUp: false, offer: false, curl: true };
    case "walking":
      return { headTilt: 0, legSpread: 8, legOffset: 6, limbUp: false, offer: false, curl: false };
    case "reaching":
      return { headTilt: -10, legSpread: 6, legOffset: 0, limbUp: true, offer: false, curl: false };
    case "perched":
      return { headTilt: 0, legSpread: 6, legOffset: 0, limbUp: false, offer: false, curl: false };
    // + NEW POSE: add a branch here returning the transform knobs.
    default:
      return { headTilt: 0, legSpread: 6, legOffset: 0, limbUp: false, offer: false, curl: false };
  }
}

function heldSpot(p: PoseInfo): { x: number; y: number } {
  if (p.curl) return { x: 4, y: -10 };
  if (p.offer) return { x: 24, y: -16 };
  return { x: 17, y: -11 };
}

/** The shared expressive face: cream eye with a highlight that blinks, a soft
 *  blush, and a gentle smile. cx/cy = head centre in the head-group's space. */
function Face({
  uid,
  eyeX,
  eyeY,
  blushX,
  smileX,
  smileY,
  dark = false,
}: {
  uid: string;
  eyeX: number;
  eyeY: number;
  blushX: number;
  smileX: number;
  smileY: number;
  dark?: boolean;
}) {
  return (
    <g>
      {/* soft cheek blush */}
      <ellipse cx={blushX} cy={eyeY + 5} rx="3" ry="2" fill={C.blush} opacity="0.5" />
      {/* eye — blinks occasionally */}
      <g className={`${uid}-eye`}>
        <ellipse cx={eyeX} cy={eyeY} rx="2.9" ry="3.2" fill={C.eye} />
        <circle cx={eyeX + 1} cy={eyeY - 1.2} r="1" fill={C.eyeHi} />
      </g>
      {/* gentle smile */}
      <path d={`M${smileX - 3} ${smileY} q3 3 6 0`} fill="none" stroke={dark ? "#0d1226" : C.eye} strokeWidth="1.3" strokeLinecap="round" opacity="0.7" />
    </g>
  );
}

/** Faint contact shadow under the feet. */
function ContactShadow() {
  return <ellipse cx="0" cy="2" rx="20" ry="5" fill="#000" opacity="0.16" filter="" />;
}

/* ---- crow -------------------------------------------------------- */
function Crow({ p, uid }: { p: PoseInfo; uid: string }) {
  const bodyDx = p.curl ? -3 : 0;
  return (
    <g>
      <ContactShadow />
      {/* legs */}
      <line x1={-p.legSpread + p.legOffset} y1="-2" x2={-p.legSpread} y2="-14" stroke={C.crow} strokeWidth="2.6" strokeLinecap="round" />
      <line x1={p.legSpread - p.legOffset} y1="-2" x2={p.legSpread} y2="-14" stroke={C.crow} strokeWidth="2.6" strokeLinecap="round" />
      {/* body */}
      <ellipse cx={bodyDx} cy={p.curl ? -22 : -24} rx={p.curl ? 24 : 22} ry={p.curl ? 18 : 16} fill={C.crow} />
      {/* rim light on the upper-right */}
      <path d={`M${bodyDx + 4} -36 q16 4 16 16`} fill="none" stroke={C.wing} strokeWidth="3" strokeLinecap="round" opacity="0.8" />
      {/* wing — extends forward when offering / lifts when reaching */}
      {p.offer ? (
        <path d={`M${bodyDx + 4} -26 q18 -4 30 6 q-12 8 -28 2 z`} fill={C.wing} />
      ) : p.limbUp ? (
        <path d={`M${bodyDx + 2} -30 q14 -16 8 -32 q-12 6 -16 26 z`} fill={C.wing} />
      ) : (
        <ellipse cx={bodyDx + 5} cy={p.curl ? -22 : -24} rx="13" ry={p.curl ? 14 : 11} fill={C.wing} />
      )}
      {/* head group (tilts for looking_up) */}
      <g transform={`translate(${bodyDx - 12} -38) rotate(${p.headTilt})`}>
        <circle cx="0" cy="0" r="13" fill={C.crow} />
        <ellipse cx="3" cy="-5" rx="6" ry="4" fill={C.wing} opacity="0.6" />
        <path d="M-12 0 l-13 3 l13 4 z" fill={C.amber} />
        <Face uid={uid} eyeX={-3} eyeY={-2} blushX={-7} smileX={-9} smileY={4} />
      </g>
    </g>
  );
}

/* ---- fox --------------------------------------------------------- */
// + NEW ANIMAL: copy this pattern (one helper) and add a case in <Body>.
function Fox({ p, uid }: { p: PoseInfo; uid: string }) {
  const bodyDx = p.curl ? -3 : 0;
  return (
    <g>
      <ContactShadow />
      {/* curved tail with amber tip */}
      <path d={`M${bodyDx + 16} -22 q26 -2 30 -26 q-14 4 -22 14 q-6 6 -8 12 z`} fill={C.fox} />
      <path d={`M${bodyDx + 40} -46 q8 0 6 12 q-10 -2 -14 -6 z`} fill={C.foxBelly} />
      {/* legs */}
      <line x1={-p.legSpread + p.legOffset} y1="-2" x2={-p.legSpread} y2="-14" stroke={C.fox} strokeWidth="3.2" strokeLinecap="round" />
      <line x1={p.legSpread - p.legOffset} y1="-2" x2={p.legSpread} y2="-14" stroke={C.fox} strokeWidth="3.2" strokeLinecap="round" />
      {/* body + belly */}
      <ellipse cx={bodyDx} cy={p.curl ? -22 : -24} rx={p.curl ? 24 : 22} ry={p.curl ? 18 : 16} fill={C.fox} />
      <ellipse cx={bodyDx + 2} cy={p.curl ? -16 : -18} rx="13" ry="9" fill={C.foxBelly} />
      {/* rim light */}
      <path d={`M${bodyDx - 6} -36 q-10 4 -12 14`} fill="none" stroke={C.foxBelly} strokeWidth="2.6" strokeLinecap="round" opacity="0.7" />
      {/* forward paw when offering / raised when reaching */}
      {p.offer && <ellipse cx={bodyDx + 22} cy="-14" rx="7" ry="5" fill={C.fox} />}
      {p.limbUp && <line x1={bodyDx + 6} y1="-30" x2={bodyDx + 12} y2="-50" stroke={C.fox} strokeWidth="4.2" strokeLinecap="round" />}
      {/* head group */}
      <g transform={`translate(${bodyDx - 12} -38) rotate(${p.headTilt})`}>
        {/* ears */}
        <path d="M-9 -9 l-3 -13 l10 6 z" fill={C.fox} />
        <path d="M5 -10 l3 -13 l-10 7 z" fill={C.fox} />
        <path d="M-7 -10 l-1 -7 l5 4 z" fill={C.crow} opacity="0.45" />
        <circle cx="0" cy="0" r="13" fill={C.fox} />
        <ellipse cx="3" cy="-5" rx="6" ry="4" fill={C.foxBelly} opacity="0.5" />
        {/* muzzle */}
        <path d="M-12 1 l-10 3 l10 4 z" fill={C.foxBelly} />
        <circle cx="-21" cy="4" r="2.2" fill={C.crow} />
        <Face uid={uid} eyeX={-3} eyeY={-2} blushX={-8} smileX={-12} smileY={5} />
      </g>
    </g>
  );
}

/* ---- little bird ------------------------------------------------- */
function LittleBird({ p, uid }: { p: PoseInfo; uid: string }) {
  const bodyDx = p.curl ? -2 : 0;
  return (
    <g transform="scale(0.74)">
      <ContactShadow />
      <line x1={-p.legSpread + p.legOffset} y1="-2" x2={-p.legSpread} y2="-12" stroke={C.outline} strokeWidth="2.6" strokeLinecap="round" />
      <line x1={p.legSpread - p.legOffset} y1="-2" x2={p.legSpread} y2="-12" stroke={C.outline} strokeWidth="2.6" strokeLinecap="round" />
      <ellipse cx={bodyDx} cy={p.curl ? -20 : -22} rx={p.curl ? 22 : 21} ry={p.curl ? 18 : 16} fill={C.bird} />
      <ellipse cx={bodyDx + 2} cy={p.curl ? -16 : -17} rx="11" ry="8" fill="#A8CEF1" />
      <path d={`M${bodyDx + 4} -34 q14 4 14 14`} fill="none" stroke="#A8CEF1" strokeWidth="2.4" strokeLinecap="round" opacity="0.7" />
      {p.offer ? (
        <path d={`M${bodyDx + 4} -24 q16 -2 24 8 q-12 6 -22 0 z`} fill={C.birdWing} />
      ) : p.limbUp ? (
        <path d={`M${bodyDx} -28 q12 -14 6 -28 q-10 6 -12 22 z`} fill={C.birdWing} />
      ) : (
        <ellipse cx={bodyDx + 4} cy={p.curl ? -20 : -22} rx="11" ry={p.curl ? 13 : 10} fill={C.birdWing} />
      )}
      <g transform={`translate(${bodyDx - 11} -34) rotate(${p.headTilt})`}>
        <circle cx="0" cy="0" r="13" fill={C.bird} />
        <ellipse cx="3" cy="-5" rx="6" ry="4" fill="#A8CEF1" opacity="0.7" />
        <path d="M-12 0 l-10 2 l10 3 z" fill={C.amber} />
        <Face uid={uid} eyeX={-3} eyeY={-2} blushX={-7} smileX={-9} smileY={4} />
      </g>
    </g>
  );
}

/* ---- rabbit ------------------------------------------------------ */
function Rabbit({ p, uid }: { p: PoseInfo; uid: string }) {
  const bodyDx = p.curl ? -3 : 0;
  return (
    <g>
      <ContactShadow />
      {/* tiny round tail */}
      <circle cx={bodyDx + 18} cy="-18" r="6.5" fill="#F0EEE6" />
      <line x1={-p.legSpread + p.legOffset} y1="-2" x2={-p.legSpread} y2="-12" stroke={C.rabbitDeep} strokeWidth="3.6" strokeLinecap="round" />
      <line x1={p.legSpread - p.legOffset} y1="-2" x2={p.legSpread} y2="-12" stroke={C.rabbitDeep} strokeWidth="3.6" strokeLinecap="round" />
      <ellipse cx={bodyDx} cy={p.curl ? -22 : -24} rx={p.curl ? 24 : 21} ry={p.curl ? 18 : 17} fill={C.rabbit} />
      <ellipse cx={bodyDx + 1} cy={p.curl ? -17 : -19} rx="11" ry="8" fill="#EFEDE6" />
      {p.offer && <ellipse cx={bodyDx + 20} cy="-14" rx="7" ry="5" fill={C.rabbit} />}
      {p.limbUp && <line x1={bodyDx + 4} y1="-30" x2={bodyDx + 8} y2="-50" stroke={C.rabbit} strokeWidth="5" strokeLinecap="round" />}
      <g transform={`translate(${bodyDx - 11} -40) rotate(${p.headTilt})`}>
        {/* two long ears, gently swaying with the body */}
        <ellipse cx="-4" cy="-22" rx="4.5" ry="15" fill={C.rabbit} transform="rotate(-10)" />
        <ellipse cx="6" cy="-22" rx="4.5" ry="15" fill={C.rabbit} transform="rotate(10)" />
        <ellipse cx="-4" cy="-22" rx="2" ry="10" fill={C.rabbitNose} opacity="0.55" transform="rotate(-10)" />
        <ellipse cx="6" cy="-22" rx="2" ry="10" fill={C.rabbitNose} opacity="0.55" transform="rotate(10)" />
        <circle cx="0" cy="0" r="13" fill={C.rabbit} />
        <ellipse cx="3" cy="-5" rx="6" ry="4" fill="#EFEDE6" opacity="0.8" />
        <circle cx="-9" cy="3" r="2.2" fill={C.rabbitNose} />
        <Face uid={uid} eyeX={-3} eyeY={-2} blushX={-7} smileX={-9} smileY={5} />
      </g>
    </g>
  );
}

/* ---- child (deliberately abstract / non-specific) --------------- */
function Child({ p, uid }: { p: PoseInfo; uid: string }) {
  const bodyDx = p.curl ? -3 : 0;
  return (
    <g>
      <ContactShadow />
      {/* legs */}
      <line x1={-p.legSpread + p.legOffset} y1="-2" x2={-p.legSpread + 1} y2="-16" stroke={C.childDeep} strokeWidth="4.4" strokeLinecap="round" />
      <line x1={p.legSpread - p.legOffset} y1="-2" x2={p.legSpread - 1} y2="-16" stroke={C.childDeep} strokeWidth="4.4" strokeLinecap="round" />
      {/* soft rounded body (little nightgown) */}
      <path d={`M${bodyDx - 13} ${p.curl ? -36 : -40} q13 -6 26 0 l3 ${p.curl ? 24 : 28} q-16 6 -32 0 z`} fill={C.child} />
      <path d={`M${bodyDx - 11} ${p.curl ? -36 : -40} q11 -5 22 0`} fill="none" stroke={C.amberLight} strokeWidth="2" opacity="0.6" />
      {/* an arm — extended for offering / raised for reaching */}
      {p.offer && <line x1={bodyDx + 8} y1="-30" x2={bodyDx + 24} y2="-30" stroke={C.child} strokeWidth="4.2" strokeLinecap="round" />}
      {p.limbUp && <line x1={bodyDx + 8} y1="-34" x2={bodyDx + 16} y2="-54" stroke={C.child} strokeWidth="4.2" strokeLinecap="round" />}
      {/* head — round, soft hair cap, gentle face */}
      <g transform={`translate(${bodyDx} -52) rotate(${p.headTilt * 0.5})`}>
        <circle cx="0" cy="0" r="13" fill="#F2D2A4" />
        {/* soft hair */}
        <path d="M-13 -2 q0 -16 13 -16 q13 0 13 16 q-6 -7 -13 -7 q-7 0 -13 7 z" fill={C.childDeep} />
        {/* two eyes + a smile (kept abstract — never a specific child) */}
        <g className={`${uid}-eye`}>
          <ellipse cx="-4.5" cy="0" rx="1.8" ry="2.2" fill={C.eye} />
          <ellipse cx="4.5" cy="0" rx="1.8" ry="2.2" fill={C.eye} />
        </g>
        <ellipse cx="-7" cy="4" rx="2.6" ry="1.7" fill={C.blush} opacity="0.55" />
        <ellipse cx="7" cy="4" rx="2.6" ry="1.7" fill={C.blush} opacity="0.55" />
        <path d="M-3.5 5 q3.5 4 7 0" fill="none" stroke={C.eye} strokeWidth="1.4" strokeLinecap="round" opacity="0.75" />
      </g>
    </g>
  );
}

/** Dispatch a character type → its hand-built helper. */
function Body({ type, p, uid }: { type: CharacterType | string; p: PoseInfo; uid: string }) {
  switch (type) {
    case "crow":
      return <Crow p={p} uid={uid} />;
    case "fox":
      return <Fox p={p} uid={uid} />;
    case "little_bird":
      return <LittleBird p={p} uid={uid} />;
    case "rabbit":
      return <Rabbit p={p} uid={uid} />;
    case "child":
      return <Child p={p} uid={uid} />;
    // + NEW ANIMAL: add a case here pointing at a new helper above.
    default:
      // unknown type → crow (the canonical hero)
      return <Crow p={p} uid={uid} />;
  }
}

/* ================================================================== */
/* CHARACTER PLACEMENT                                                 */
/* ================================================================== */

function PlacedCharacter({
  c,
  x,
  ground,
  faceLeft,
  uid,
  idx,
}: {
  c: Character;
  x: number;
  ground: number;
  faceLeft?: boolean;
  uid: string;
  idx: number;
}) {
  const scale = (c.size === "big" ? 1.5 : 1) * 1.08;
  const p = poseInfo(c.pose);
  const flip = faceLeft ? -1 : 1;
  const spot = heldSpot(p);
  return (
    // outer group: a gentle idle bob (different phase per character)
    <g className={`${uid}-char2`} style={{ animationDelay: `${idx * 1.1}s` }}>
      {/* a soft warm rim-light wash behind the character for depth */}
      <g transform={`translate(${x} ${ground})`}>
        {/* breathing group */}
        <g className={`${uid}-char`} style={{ animationDelay: `${idx * 0.9}s` }}>
          <g transform={`scale(${flip * scale} ${scale})`}>
            <Body type={c.type} p={p} uid={uid} />
            {c.holding != null && (
              <g transform={`translate(${spot.x} ${spot.y}) scale(${flip} 1)`}>
                <HeldObject holding={c.holding} uid={uid} />
              </g>
            )}
          </g>
        </g>
      </g>
    </g>
  );
}

/* ================================================================== */
/* SCENE                                                              */
/* ================================================================== */

let sceneCounter = 0;

export default function Scene({ spec, className }: { spec: SceneSpec; className?: string }) {
  // a stable, unique id per mounted Scene so gradient/filter/animation ids
  // and @keyframes names never collide when two Scenes render at once.
  const uid = useMemo(() => `sc${(sceneCounter++).toString(36)}${Math.floor(Math.random() * 1e4).toString(36)}`, []);

  // Defensive defaults — a malformed spec must still render something warm.
  const setting: Setting | string = spec?.setting ?? "night_branch";
  const props: Array<Prop | string> = Array.isArray(spec?.props) ? spec.props : [];
  const characters: Character[] = Array.isArray(spec?.characters) ? spec.characters : [];
  const mood: Mood | string = spec?.mood ?? "tender";
  const ml = moodLight(mood);
  const ground = groundFor(setting);

  const hasMoon = props.includes("moon");
  const hasStars = props.includes("stars");
  // open sky & golden-hour scenes earn god-rays; tuck the light up-left there
  // for the sky, up-right otherwise.
  const wantRays = setting === "open_sky" || isWarmDay(ml.day);
  const lightX = setting === "open_sky" ? 232 : 252;
  const lightY = setting === "open_sky" ? 56 : 52;

  // Layout: one character centred; a pair faces each other so they don't
  // overlap (a big one offering toward a small one looking up reads naturally).
  const positions = characters.length <= 1 ? [160] : [108, 214];
  const facing = characters.length <= 1 ? [false] : [false, true];

  return (
    <svg
      className={`${uid}-root ${className ?? ""}`.trim()}
      viewBox="0 0 320 220"
      preserveAspectRatio="xMidYMid slice"
      role="img"
      aria-label={`A storybook scene set in ${typeof setting === "string" ? setting.replace(/_/g, " ") : "a quiet place"}`}
      style={{ display: "block", width: "100%", height: "100%" }}
    >
      <Defs uid={uid} ml={ml} />
      <Styles uid={uid} />

      {/* everything clipped to the rounded card */}
      <g clipPath={`url(#${uid}-clip)`}>
        {/* graded sky */}
        <rect x="0" y="0" width="320" height="220" fill={`url(#${uid}-sky)`} />

        {/* atmospheric clouds high in the sky (behind everything) */}
        <Clouds uid={uid} ml={ml} />

        {/* stars (default-on for cool/night reads even without the prop, so the
            sky never feels empty; the moon only when asked) */}
        {(hasStars || ml.day === "night" || ml.day === "blue" || ml.day === "moon") && (
          <Stars uid={uid} ml={ml} />
        )}

        {/* the light source: explicit moon, or an ambient sun for warm days */}
        {(hasMoon || isWarmDay(ml.day)) && (
          <LightSource uid={uid} ml={ml} x={lightX} y={lightY} rays={wantRays} />
        )}

        {/* setting backdrop (hills → midground → foreground floor) */}
        <Backdrop setting={setting} uid={uid} ml={ml} />

        {/* floating dust motes in the air for depth & magic */}
        <DustMotes uid={uid} ml={ml} />

        {/* ground-level + ambient props (drawn on top of the floor) */}
        {props
          .filter((pr) => pr !== "moon" && pr !== "stars")
          .map((pr, i) => (
            <PropLayer key={`${pr}-${i}`} prop={pr} uid={uid} ground={ground} />
          ))}

        {/* characters */}
        {characters.slice(0, 2).map((c, i) => (
          <PlacedCharacter
            key={i}
            c={c}
            x={positions[i] ?? 160}
            ground={ground}
            faceLeft={facing[i]}
            uid={uid}
            idx={i}
          />
        ))}

        {/* atmospheric warm/cool wash (never anything scary) */}
        <rect
          x="0"
          y="0"
          width="320"
          height="220"
          fill={ml.warmOverlay}
          opacity={ml.warmOpacity}
          pointerEvents="none"
          style={{ mixBlendMode: "soft-light" } as React.CSSProperties}
        />

        {/* soft vignette frames the cozy little world */}
        <rect x="0" y="0" width="320" height="220" fill={`url(#${uid}-vig)`} pointerEvents="none" />
      </g>
    </svg>
  );
}
